package com.trademaster.ims.mobile.fulfillment;

import com.trademaster.ims.mobile.auth.service.CustomerAuthException;import com.trademaster.ims.mobile.checkout.model.*;import com.trademaster.ims.mobile.checkout.repository.*;import com.trademaster.ims.mobile.fulfillment.dto.FulfillmentDtos.*;import com.trademaster.ims.mobile.fulfillment.model.*;import com.trademaster.ims.mobile.fulfillment.repository.*;import com.trademaster.ims.mobile.fulfillment.service.OrderFulfillmentService;import com.trademaster.ims.mobile.payments.model.*;import com.trademaster.ims.mobile.payments.repository.*;import com.trademaster.ims.model.*;import com.trademaster.ims.repository.*;import org.junit.jupiter.api.*;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.*;import org.mockito.junit.jupiter.MockitoExtension;import org.mockito.junit.jupiter.MockitoSettings;import org.mockito.quality.Strictness;import org.springframework.test.util.ReflectionTestUtils;import java.math.BigDecimal;import java.time.*;import java.util.*;import static org.assertj.core.api.Assertions.*;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)@MockitoSettings(strictness=Strictness.LENIENT)class OrderFulfillmentServiceTest{
 @Mock CustomerOrderRepository orders;@Mock CustomerOrderItemRepository items;@Mock CustomerOrderStatusHistoryRepository orderHistory;@Mock OrderFulfillmentRepository fulfillments;@Mock FulfillmentStatusHistoryRepository fulfillmentHistory;@Mock DeliveryEventRepository deliveryEvents;@Mock CODCollectionRepository codCollections;@Mock InventoryRepository inventory;@Mock StockMovementRepository stockMovements;@Mock WarehouseRepository warehouses;@Mock CustomerPaymentRepository payments;@Mock PaymentStatusHistoryRepository paymentHistory;@Mock FinancialAccountRepository accounts;@Mock AccountLedgerEntryRepository ledgers;OrderFulfillmentService service;
 @BeforeEach void setup(){service=new OrderFulfillmentService(orders,items,orderHistory,fulfillments,fulfillmentHistory,deliveryEvents,codCollections,inventory,stockMovements,warehouses,payments,paymentHistory,accounts,ledgers);lenient().when(fulfillments.saveAndFlush(any())).thenAnswer(i->{OrderFulfillment f=i.getArgument(0);if(f.getId()==null)ReflectionTestUtils.setField(f,"id",11L);return f;});lenient().when(fulfillments.save(any())).thenAnswer(i->{OrderFulfillment f=i.getArgument(0);if(f.getId()==null)ReflectionTestUtils.setField(f,"id",11L);return f;});lenient().when(fulfillmentHistory.save(any())).thenAnswer(i->i.getArgument(0));lenient().when(deliveryEvents.save(any())).thenAnswer(i->{DeliveryEvent e=i.getArgument(0);if(e.getId()==null)ReflectionTestUtils.setField(e,"id",30L);return e;});lenient().when(orderHistory.save(any())).thenAnswer(i->i.getArgument(0));lenient().when(stockMovements.save(any())).thenAnswer(i->i.getArgument(0));lenient().when(codCollections.save(any())).thenAnswer(i->{CODCollection c=i.getArgument(0);if(c.getId()==null)ReflectionTestUtils.setField(c,"id",40L);return c;});lenient().when(payments.save(any())).thenAnswer(i->i.getArgument(0));}
 @Test void paidPostedConfirmedOrderCanStartProcessing(){CustomerOrder o=order(CustomerOrder.PaymentStatus.PAID,CustomerOrder.AccountingStatus.POSTED,CustomerOrder.OrderStatus.CONFIRMED);when(orders.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(o));when(fulfillments.lockByOrderNumber("TSS-1")).thenReturn(Optional.empty());when(fulfillments.existsByFulfillmentNumber(anyString())).thenReturn(false);when(warehouses.findByStatus("ACTIVE")).thenReturn(List.of(warehouse()));FulfillmentDetail r=service.startProcessing("TSS-1",new TransitionRequest(null,"Preparing order",null,null,null,null,null,null,null),"admin");assertThat(r.fulfillmentStatus()).isEqualTo("PROCESSING");assertThat(o.getStatus()).isEqualTo(CustomerOrder.OrderStatus.PROCESSING);verify(orderHistory).save(argThat(h->"PROCESSING".equals(h.getStatus())));}
 @Test void unpaidNonCodOrderCannotStartProcessing(){CustomerOrder o=order(CustomerOrder.PaymentStatus.REVIEW_REQUIRED,CustomerOrder.AccountingStatus.UNPOSTED,CustomerOrder.OrderStatus.CONFIRMED);when(orders.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(o));assertThatThrownBy(()->service.startProcessing("TSS-1",null,"admin")).isInstanceOf(CustomerAuthException.class).hasMessageContaining("not ready");verify(fulfillments,never()).save(any());}
 @Test void packDeductsStockExactlyOnceAndCreatesMovement(){CustomerOrder o=order(CustomerOrder.PaymentStatus.PAID,CustomerOrder.AccountingStatus.POSTED,CustomerOrder.OrderStatus.PROCESSING);OrderFulfillment f=fulfillment(o,OrderFulfillment.FulfillmentStatus.PROCESSING);CustomerOrderItem item=item(5L,2);Inventory inv=new Inventory(1L,1L,5L,10);when(fulfillments.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(f));when(orders.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(o));when(warehouses.findById(1L)).thenReturn(Optional.of(warehouse()));when(items.findByOrderIdOrderByIdAsc(1L)).thenReturn(List.of(item));when(stockMovements.existsByReferenceNoAndMovementType(anyString(),eq(StockMovement.MovementType.CUSTOMER_ORDER_FULFILLMENT))).thenReturn(false);when(inventory.findByProductIdAndWarehouseId(5L,1L)).thenReturn(Optional.of(inv));FulfillmentDetail r=service.pack("TSS-1",null,"warehouse");assertThat(r.fulfillmentStatus()).isEqualTo("PACKED");assertThat(inv.getQuantity()).isEqualTo(8);assertThat(f.isStockDeducted()).isTrue();verify(stockMovements,times(1)).save(argThat(m->m.getQuantity()==-2&&m.getMovementType()==StockMovement.MovementType.CUSTOMER_ORDER_FULFILLMENT));}
 @Test void duplicatePackDoesNotDeductAgain(){CustomerOrder o=order(CustomerOrder.PaymentStatus.PAID,CustomerOrder.AccountingStatus.POSTED,CustomerOrder.OrderStatus.PACKED);OrderFulfillment f=fulfillment(o,OrderFulfillment.FulfillmentStatus.PACKED);f.setStockDeducted(true);when(fulfillments.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(f));when(orders.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(o));FulfillmentDetail r=service.pack("TSS-1",null,"warehouse");assertThat(r.fulfillmentStatus()).isEqualTo("PACKED");verify(stockMovements,never()).save(any());}
 @Test void insufficientStockBlocksPackWithoutMovement(){CustomerOrder o=order(CustomerOrder.PaymentStatus.PAID,CustomerOrder.AccountingStatus.POSTED,CustomerOrder.OrderStatus.PROCESSING);OrderFulfillment f=fulfillment(o,OrderFulfillment.FulfillmentStatus.PROCESSING);when(fulfillments.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(f));when(orders.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(o));when(warehouses.findById(1L)).thenReturn(Optional.of(warehouse()));when(items.findByOrderIdOrderByIdAsc(1L)).thenReturn(List.of(item(5L,9)));when(inventory.findByProductIdAndWarehouseId(5L,1L)).thenReturn(Optional.of(new Inventory(1L,1L,5L,2)));assertThatThrownBy(()->service.pack("TSS-1",null,"warehouse")).isInstanceOf(CustomerAuthException.class).hasMessageContaining("available");verify(stockMovements,never()).save(any());}
 @Test void customerTrackingFiltersInternalEvents(){CustomerOrder o=order(CustomerOrder.PaymentStatus.PAID,CustomerOrder.AccountingStatus.POSTED,CustomerOrder.OrderStatus.SHIPPED);OrderFulfillment f=fulfillment(o,OrderFulfillment.FulfillmentStatus.SHIPPED);DeliveryEvent visible=event(true,"Visible");when(orders.findByOrderNumberAndAccountId("TSS-1",7L)).thenReturn(Optional.of(o));when(fulfillments.findByOrder_Id(1L)).thenReturn(Optional.of(f));when(deliveryEvents.findByFulfillmentIdAndCustomerVisibleTrueOrderByOccurredAtAsc(11L)).thenReturn(List.of(visible));when(orderHistory.findByOrderIdOrderByCreatedAtAsc(1L)).thenReturn(List.of(history("CONFIRMED"),history("PROCESSING"),history("PACKED"),history("SHIPPED")));OrderTrackingResponse r=service.customerTracking(7L,"TSS-1");assertThat(r.deliveryEvents()).hasSize(1);assertThat(r.deliveryEvents().get(0).title()).isEqualTo("Visible");assertThat(r.steps()).extracting(TrackingStep::key).contains("SHIPPED","DELIVERED");}
 @Test void codDeliveryRequiresExactAmountAndPostsOnce(){CustomerOrder o=order(CustomerOrder.PaymentStatus.COD_PENDING,CustomerOrder.AccountingStatus.UNPOSTED,CustomerOrder.OrderStatus.OUT_FOR_DELIVERY);OrderFulfillment f=fulfillment(o,OrderFulfillment.FulfillmentStatus.OUT_FOR_DELIVERY);CustomerPayment p=payment();FinancialAccount fa=new FinancialAccount();fa.setAccountId(1L);fa.setStatus(FinancialAccount.AccountStatus.ACTIVE);fa.setCurrentBalance(BigDecimal.ZERO);when(fulfillments.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(f));when(orders.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(o));when(payments.findTopByOrderIdOrderByCreatedAtDesc(1L)).thenReturn(Optional.of(p));when(payments.existsByPostingKey("CUSTOMER_PAYMENT:PAY-1")).thenReturn(false);when(accounts.findAll()).thenReturn(List.of(fa));when(ledgers.save(any())).thenAnswer(i->{AccountLedgerEntry e=i.getArgument(0);ReflectionTestUtils.setField(e,"ledgerEntryId",90L);return e;});FulfillmentDetail r=service.deliver("TSS-1",new TransitionRequest(null,null,null,null,null,null,null,null,new BigDecimal("185.00")),"rider");assertThat(r.fulfillmentStatus()).isEqualTo("DELIVERED");assertThat(o.getPaymentStatus()).isEqualTo(CustomerOrder.PaymentStatus.PAID);assertThat(p.getAccountingStatus()).isEqualTo(CustomerPayment.AccountingStatus.POSTED);verify(ledgers,times(1)).save(any());}
 @Test void codAmountMismatchBlocksDelivery(){CustomerOrder o=order(CustomerOrder.PaymentStatus.COD_PENDING,CustomerOrder.AccountingStatus.UNPOSTED,CustomerOrder.OrderStatus.OUT_FOR_DELIVERY);OrderFulfillment f=fulfillment(o,OrderFulfillment.FulfillmentStatus.OUT_FOR_DELIVERY);when(fulfillments.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(f));when(orders.lockByOrderNumber("TSS-1")).thenReturn(Optional.of(o));when(payments.findTopByOrderIdOrderByCreatedAtDesc(1L)).thenReturn(Optional.of(payment()));assertThatThrownBy(()->service.deliver("TSS-1",new TransitionRequest(null,null,null,null,null,null,null,null,new BigDecimal("100.00")),"rider")).isInstanceOf(CustomerAuthException.class).hasMessageContaining("does not match");assertThat(f.getStatus()).isEqualTo(OrderFulfillment.FulfillmentStatus.OUT_FOR_DELIVERY);verify(ledgers,never()).save(any());}
 private CustomerOrder order(CustomerOrder.PaymentStatus ps,CustomerOrder.AccountingStatus as,CustomerOrder.OrderStatus os){CustomerOrder o=new CustomerOrder();ReflectionTestUtils.setField(o,"id",1L);o.setAccountId(7L);o.setOrderNumber("TSS-1");o.setPaymentStatus(ps);o.setAccountingStatus(as);o.setStatus(os);o.setTotal(new BigDecimal("185.00"));o.setDeliverySnapshot("Home delivery");o.setSubmittedAt(Instant.now());return o;}private Warehouse warehouse(){Warehouse w=new Warehouse();w.setId(1L);w.setName("Main");w.setStatus("ACTIVE");return w;}private OrderFulfillment fulfillment(CustomerOrder o,OrderFulfillment.FulfillmentStatus s){OrderFulfillment f=new OrderFulfillment();ReflectionTestUtils.setField(f,"id",11L);f.setFulfillmentNumber("FUL-1");f.setOrder(o);f.setOrderNumber(o.getOrderNumber());f.setWarehouseId(1L);f.setStatus(s);return f;}private CustomerOrderItem item(Long product,int qty){CustomerOrderItem i=new CustomerOrderItem();ReflectionTestUtils.setField(i,"id",21L);i.setOrderId(1L);i.setProductId(product);i.setQuantity(qty);return i;}private CustomerOrderStatusHistory history(String status){CustomerOrderStatusHistory h=new CustomerOrderStatusHistory();h.setStatus(status);h.setCreatedAt(Instant.now());return h;}private DeliveryEvent event(boolean visible,String title){DeliveryEvent e=new DeliveryEvent();ReflectionTestUtils.setField(e,"id",31L);e.setFulfillmentId(11L);e.setEventType(DeliveryEvent.EventType.NOTE);e.setTitle(title);e.setDescription(title);e.setCustomerVisible(visible);e.setOccurredAt(Instant.now());return e;}private CustomerPayment payment(){CustomerPayment p=new CustomerPayment();ReflectionTestUtils.setField(p,"id",70L);p.setPaymentNumber("PAY-1");p.setOrderId(1L);p.setOrderNumber("TSS-1");p.setAccountId(7L);p.setAmount(new BigDecimal("185.00"));p.setMethodCode("CASH_ON_DELIVERY");p.setMethodType("CASH_ON_DELIVERY");p.setPaymentStatus(CustomerPayment.PaymentStatus.COD_PENDING);return p;}
}